public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret = next insertEntityDataSource(_entityCtx, _dataSourceCtx);

    if(ret)
    {
        if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
        {
            switch (_dataSourceCtx.name())
            {
                case dataEntityDataSourceStr(LogisticsAddressCountryRegionEntity, LogisticsAddressCountryRegion) :
                    LogisticsAddressCountryRegion logisticsAddressCountryRegion = _dataSourceCtx.getBuffer() as LogisticsAddressCountryRegion;

                    ttsbegin;
                    LogisticsAddressCountryRegionEntity::updateLACRTranslationEntityFields(
                logisticsAddressCountryRegion.CountryRegionId,
                logisticsAddressCountryRegion.ETGLanguageId,
                logisticsAddressCountryRegion.ETGLongName,
                logisticsAddressCountryRegion.ETGShortName);
                    ttscommit;

                    break;
            }
        }
    }

    return ret;
}

public boolean updateEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret = next updateEntityDataSource(_entityCtx, _dataSourceCtx);

    if(ret)
    {
        if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
        {
            switch (_dataSourceCtx.name())
            {
                case dataEntityDataSourceStr(LogisticsAddressCountryRegionEntity, LogisticsAddressCountryRegion) :
                    LogisticsAddressCountryRegion logisticsAddressCountryRegion = _dataSourceCtx.getBuffer() as LogisticsAddressCountryRegion;

                    ttsbegin;
                    LogisticsAddressCountryRegionEntity::updateLACRTranslationEntityFields(
                logisticsAddressCountryRegion.CountryRegionId,
                logisticsAddressCountryRegion.ETGLanguageId,
                logisticsAddressCountryRegion.ETGLongName,
                logisticsAddressCountryRegion.ETGShortName);
                    ttscommit;

                    break;
            }
        }
    }

    return ret;
}

public static void updateLACRTranslationEntityFields(String50 countryRegionId, LanguageId languageId, String255 longName, String255 shortName)
{
    LogisticsAddressCountryRegionTranslation  logisticsAddressCountryRegionTranslation;
    LogisticsAddressCountryRegion             logisticsAddressCountryRegion;

    select forupdate logisticsAddressCountryRegionTranslation
        where logisticsAddressCountryRegionTranslation.CountryRegionId == countryRegionId
         && logisticsAddressCountryRegionTranslation.LanguageId == languageId;

    if (logisticsAddressCountryRegionTranslation.RecId)
    {
        logisticsAddressCountryRegionTranslation.LongName = longName;
        logisticsAddressCountryRegionTranslation.ShortName = shortName;
        logisticsAddressCountryRegionTranslation.update();
    }
    else
    {
        logisticsAddressCountryRegionTranslation.clear();
        logisticsAddressCountryRegionTranslation.CountryRegionId = countryRegionId;
        logisticsAddressCountryRegionTranslation.LanguageId      = languageId;
        logisticsAddressCountryRegionTranslation.LongName = longName;
        logisticsAddressCountryRegionTranslation.ShortName = shortName;
        logisticsAddressCountryRegionTranslation.insert();

    }   
}
